#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define fp float
#define EQUATIONS 91

void embedded_fehlberg_7_8(fp timeinst,
                           fp h,
                           fp* initvalu,
                           fp* finavalu,
                           fp* error,
                           fp* parameter,
                           fp* com,

                           fp* d_initvalu,
                           fp* d_finavalu,
                           fp* d_params,
                           fp* d_com);

int solver(fp** y,
           fp* x,
           int xmax,
           fp* params,
           fp* com,

           fp* d_initvalu,
           fp* d_finavalu,
           fp* d_params,
           fp* d_com);

int solver_2(fp** y,
             fp* x,
             int xmax,
             fp* params,
             fp* com,

             fp* d_initvalu,
             fp* d_finavalu,
             fp* d_params,
             fp* d_com) {
  return solver(y, x, xmax, params, com, d_initvalu, d_finavalu, d_params, d_com);
}

int solver(fp** y,
           fp* x,
           int xmax,
           fp* params,
           fp* com,

           fp* d_initvalu,
           fp* d_finavalu,
           fp* d_params,
           fp* d_com) {

  fp err_exponent;
  int error;
  int outside;
  fp h;
  fp h_init;
  fp tolerance;
  int xmin;

  fp scale_min;
  fp scale_fina;
  fp* err = (fp*)malloc(EQUATIONS * sizeof(fp));
  fp* scale = (fp*)malloc(EQUATIONS * sizeof(fp));
  fp* yy = (fp*)malloc(EQUATIONS * sizeof(fp));

  int i, j, k;

  err_exponent = 1.0 / 7.0;
  h_init = 1;
  h = h_init;
  xmin = 0;
  tolerance = 10 / (fp)(xmax - xmin);

  x[0] = 0;

  if (xmin > xmax || 0.0 >= h) {
    free(err);
    free(scale);
    free(yy);
    return -2;
  }

  if (xmin == xmax) {
    free(err);
    free(scale);
    free(yy);
    return 0;
  }

  if ((xmax - xmin) < h) {
    h = (fp)xmax - (fp)xmin;
  }

  printf("Time Steps: ");
  fflush(0);

  for (k = 1; xmax >= k; k++) {
    x[k] = k - 1;
    h = h_init;

    scale_fina = 1.0;

    for (j = 0; j < 12; j++) {
      error = 0;
      outside = 0;
      scale_min = 4.0;

      embedded_fehlberg_7_8(x[k],
                            h,
                            y[k - 1],
                            y[k],
                            err,
                            params,
                            com,

                            d_initvalu,
                            d_finavalu,
                            d_params,
                            d_com);

      for (i = 0; i < EQUATIONS; i++) {
        if (0 < err[i]) {
          error = 1;
        }
      }
      if (1 != error) {
        scale_fina = 4.0;
        break;
      }

      for (i = 0; i < EQUATIONS; i++) {
        if (0.0 == y[k - 1][i]) {
          yy[i] = tolerance;
        } else {
          yy[i] = fabsf(y[k - 1][i]);
        }
        scale[i] = 0.8 * powf(tolerance * yy[i] / err[i], err_exponent);
        if (scale_min > scale[i]) {
          scale_min = scale[i];
        }
      }
      scale_fina = fminf(fmaxf(scale_min, 0.125), 4.0);

      for (i = 0; i < EQUATIONS; i++) {
        if ((tolerance * yy[i]) < err[i]) {
          outside = 1;
        }
      }
      if (0 == outside) {
        break;
      }

      h = h * scale_fina;

      if (0.9 <= h) {
        h = 0.9;
      }

      if (x[k] + h > (fp)xmax) {
        h = (fp)xmax - x[k];
      } else if (x[k] + h + 0.5 * h > (fp)xmax) {
        h = 0.5 * h;
      }
    }

    x[k] = x[k] + h;

    if (12 <= j) {
      free(err);
      free(scale);
      free(yy);
      return -1;
    }

    printf("%d ", k);
    fflush(0);
  }

  printf("\n");
  fflush(0);

  free(err);
  free(scale);
  free(yy);

  return 0;
}
